// JWT Validation - v2.0.0
// Fetch secret from app_config, validate Bearer token
const webhookData = $('Webhook - Update Appointment').first().json;
const jwtSecret = $('Get JWT Secret - Supabase').first().json.value;

if (!jwtSecret) {
  return [{ json: { validationPassed: 'false', errorMessage: 'JWT secret not configured', statusCode: 500 } }];
}

const authHeader = webhookData.headers?.authorization || webhookData.headers?.Authorization || '';
const token = authHeader.replace('Bearer ', '').trim();

if (!token) {
  return [{ json: { validationPassed: 'false', errorMessage: 'No authorization token provided', statusCode: 401 } }];
}

function simpleHash(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    const char = input.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString(36);
}

function verifyJWT(token, secret) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return { valid: false, error: 'Invalid token format' };
    const [header, payload, sig] = parts;
    const expected = simpleHash(header + '.' + payload + '.' + secret);
    if (sig !== expected) return { valid: false, error: 'Invalid signature' };
    const decoded = JSON.parse(atob(payload));
    const now = Math.floor(Date.now() / 1000);
    if (decoded.exp && decoded.exp < now) return { valid: false, error: 'Token expired' };
    if (decoded.type === 'limited') return { valid: false, error: 'Limited token not allowed' };
    if (decoded.type === 'refresh') return { valid: false, error: 'Refresh tokens not allowed' };
    return { valid: true, payload: decoded };
  } catch (e) {
    return { valid: false, error: 'Token verification failed' };
  }
}

const result = verifyJWT(token, jwtSecret);
if (!result.valid) {
  return [{ json: { validationPassed: 'false', errorMessage: result.error, statusCode: 401 } }];
}

return [{ json: { validationPassed: 'true', user: { id: result.payload.user_id || null, username: result.payload.sub, role: result.payload.role, tokenType: result.payload.type } } }];
// v2.0.0 - JWT validation from app_config

// Validate Request - v3.0.0
// Type-aware validation + traffic flag + fallback transit detection
const webhookData = $('Webhook - Update Appointment').first().json;
const data = webhookData.body;
const user = $('JWT Validation - Code').first().json.user;

if (!data.id) {
  return [{ json: { validationResult: 'invalid', error: 'Appointment ID is required' } }];
}
if (!data.knumber) {
  return [{ json: { validationResult: 'invalid', error: 'Client K number is required' } }];
}
if (!data.appointmentDateTime) {
  return [{ json: { validationResult: 'invalid', error: 'Appointment date/time is required' } }];
}

const appointmentType = data.appointment_type || 'round_trip';
const validTypes = ['round_trip', 'one_way', 'support'];
if (!validTypes.includes(appointmentType)) {
  return [{ json: { validationResult: 'invalid', error: 'Invalid appointment_type: ' + appointmentType } }];
}

if (appointmentType === 'one_way') {
  const validDirs = ['to_clinic', 'to_home'];
  const dir = data.trip_direction || '';
  if (!validDirs.includes(dir)) {
    return [{ json: { validationResult: 'invalid', error: 'trip_direction required for one_way' } }];
  }
}

if (appointmentType === 'support') {
  if (!data.event_name || !data.event_name.trim()) {
    return [{ json: { validationResult: 'invalid', error: 'event_name required for support type' } }];
  }
}

const trafficChecked = data.calculate_traffic_transit === true || data.calculate_traffic_transit === 'true';
// Use explicit frontend flag — frontend knows whether stored travel time exists
const frontendFallbackFlag = data.needs_fallback_transit === true || data.needs_fallback_transit === 'true';
const needsFallback = (!trafficChecked && frontendFallbackFlag && appointmentType !== 'support') ? true : false;

return [{ json: {
  validationResult: 'valid',
  ...data,
  appointment_type: appointmentType,
  trip_direction: data.trip_direction || null,
  event_name: data.event_name || null,
  calculate_traffic_transit: trafficChecked,
  needs_fallback_transit: needsFallback,
  userId: user?.id || null,
  userName: user?.username || 'unknown',
  userRole: user?.role || 'unknown'
} }];
// v3.1.0 - Use explicit frontend flag instead of transitVal===30 heuristic

// Calculate Times - v2.0.0
// Type-aware timing calculations
const appointmentDateTime = new Date($json.appointmentDateTime);
const transitTime = parseInt($json.transitTime) || 30;
const appointmentLength = parseInt($json.appointmentLength) || 120;
const appointmentType = $json.appointment_type || 'round_trip';
const oneWayDirection = $json.trip_direction || 'to_clinic';

let pickupTime, dropOffTime;

if (appointmentType === 'one_way') {
  if (oneWayDirection === 'to_home') {
    pickupTime = appointmentDateTime.toISOString();
    const dropOff = new Date(appointmentDateTime.getTime() + (transitTime * 60000));
    dropOffTime = dropOff.toISOString();
  } else {
    const pickup = new Date(appointmentDateTime.getTime() - (transitTime * 60000));
    pickupTime = pickup.toISOString();
    dropOffTime = appointmentDateTime.toISOString();
  }
} else if (appointmentType === 'support') {
  pickupTime = appointmentDateTime.toISOString();
  const dropOff = new Date(appointmentDateTime.getTime() + (appointmentLength * 60000));
  dropOffTime = dropOff.toISOString();
} else {
  const pickup = new Date(appointmentDateTime.getTime() - (transitTime * 60000));
  pickupTime = pickup.toISOString();
  const totalDuration = appointmentLength + transitTime;
  const dropOff = new Date(appointmentDateTime.getTime() + (totalDuration * 60000));
  dropOffTime = dropOff.toISOString();
}

return [{ json: { ...$json, pickupTime: pickupTime, dropOffTime: dropOffTime, transitTime: transitTime, appointmentLength: appointmentLength } }];
// v2.0.0 - Type-aware timing calculations

// Compare Current vs New - v3.0.0
// Type fields, traffic flag, fallback transit, entity label
const requestData = $('Calculate Times - Code').first().json;
const currentAppointment = $input.first().json;

const hasOriginalDriver = currentAppointment.driver_assigned !== null && currentAppointment.driver_assigned !== undefined;
const hasOriginalCalendarEvent = currentAppointment.driver_calendar_event_id && currentAppointment.driver_calendar_event_id !== null;
const hasNewDriver = requestData.driver_assigned && requestData.driver_assigned !== null;
const driverChanged = currentAppointment.driver_assigned !== requestData.driver_assigned;

const hasOrphanedEvent = (!hasOriginalDriver && hasOriginalCalendarEvent) ? 'true' : 'false';
const needsDelete = (driverChanged && hasOriginalDriver && hasOriginalCalendarEvent) ? 'true' : 'false';

const calendarFieldsChanged = (
  currentAppointment.appointmenttime !== requestData.appointmentDateTime ||
  currentAppointment.pickuptime !== requestData.pickupTime ||
  currentAppointment.dropOffTime !== requestData.dropOffTime ||
  currentAppointment.locationname !== requestData.location ||
  currentAppointment.locationaddress !== requestData.locationAddress ||
  currentAppointment.scheduling_notes !== requestData.scheduling_notes ||
  currentAppointment.notes !== requestData.notes
);

const needsSync = (hasNewDriver && (driverChanged || calendarFieldsChanged)) ? 'true' : 'false';

const apptType = requestData.appointment_type || 'round_trip';
const trafficFlag = requestData.calculate_traffic_transit === true || requestData.calculate_traffic_transit === 'true';
const trafficCalcNeeded = (trafficFlag && apptType !== 'support') ? 'true' : 'false';
const fallbackNeeded = requestData.needs_fallback_transit === true ? 'true' : 'false';
const hasAsyncTask = (needsDelete === 'true' || needsSync === 'true' || trafficCalcNeeded === 'true' || fallbackNeeded === 'true') ? 'true' : 'false';

const dateStr = new Date(requestData.appointmentDateTime).toLocaleDateString('en-CA');
const entityLabel = (requestData.knumber || 'Unknown') + ' - ' + (requestData.location || 'Unknown') + ' (' + dateStr + ')';

return [{ json: {
  ...requestData,
  currentAppointment: currentAppointment,
  appointment_type: apptType,
  trip_direction: requestData.trip_direction || null,
  event_name: requestData.event_name || null,
  trafficCalcNeeded: trafficCalcNeeded,
  fallbackTransitNeeded: fallbackNeeded,
  hasAsyncTask: hasAsyncTask,
  entityLabel: entityLabel,
  calendarOperations: {
    needsDelete: needsDelete,
    needsSync: needsSync,
    hasOrphanedEvent: hasOrphanedEvent,
    originalDriverAssigned: currentAppointment.driver_assigned,
    originalCalendarEventId: currentAppointment.driver_calendar_event_id,
    newDriverAssigned: requestData.driver_assigned,
    driverChanged: driverChanged,
    calendarFieldsChanged: calendarFieldsChanged,
    hasOriginalDriver: hasOriginalDriver,
    hasOriginalCalendarEvent: hasOriginalCalendarEvent
  }
} }];
// v3.0.0 - Added fallbackTransitNeeded flag

// Decide Async Task - v2.0.0
// Includes fallback transit calc step
const data = $('Compare Current vs New - Code').first().json;
const needsDelete = data.calendarOperations.needsDelete === 'true';
const needsSync = data.calendarOperations.needsSync === 'true';
const trafficCalc = data.trafficCalcNeeded === 'true';
const fallbackCalc = data.fallbackTransitNeeded === 'true';
const hasAsyncTask = needsDelete || needsSync || trafficCalc || fallbackCalc;

const steps = [];
if (fallbackCalc) steps.push('fallback_transit_calc');
if (trafficCalc) steps.push('traffic_calc');
if (needsDelete) steps.push('calendar_delete');
if (needsSync) steps.push('calendar_sync');

return [{ json: {
  ...data,
  hasAsyncTask: hasAsyncTask ? 'true' : 'false',
  asyncSteps: steps,
  taskMetadata: hasAsyncTask ? {
    entity_type: 'appointment',
    entity_id: data.id,
    entity_label: data.entityLabel,
    task_type: 'appointment_async_ops',
    status: 'pending',
    created_by: data.userId || null
  } : null
} }];
// v2.0.0 - Added fallback_transit_calc step

// Format Async Response - v1.0.0
const data = $('Decide Async Task - Code').first().json;
const taskRow = $input.first().json;

return [{ json: { success: true, message: 'Appointment updated. Background tasks started.', data: { id: data.id, knumber: data.knumber, appointmenttime: data.appointmentDateTime, location: data.location, appointment_type: data.appointment_type || 'round_trip', trip_direction: data.trip_direction || null, event_name: data.event_name || null }, backgroundTasks: { taskId: taskRow.id || null, taskType: 'appointment_async_ops', steps: data.asyncSteps || [] }, timestamp: new Date().toISOString() } }];
// v1.0.0 - Async response with task info

// Format Simple Response - v1.0.0
const data = $('Decide Async Task - Code').first().json;

return [{ json: { success: true, message: 'Appointment updated successfully.', data: { id: data.id, knumber: data.knumber, appointmenttime: data.appointmentDateTime, location: data.location, appointment_type: data.appointment_type || 'round_trip', trip_direction: data.trip_direction || null, event_name: data.event_name || null }, backgroundTasks: null, timestamp: new Date().toISOString() } }];
// v1.0.0 - Simple response, no async tasks

// Format JWT Error - v1.0.0
const errorData = $input.first().json;
return [{ json: { success: false, message: errorData.errorMessage || 'Unauthorized', error: errorData.errorMessage || 'JWT validation failed', timestamp: new Date().toISOString() } }];
// v1.0.0 - JWT error response

// Format Validation Error - v1.0.0
const errorData = $input.first().json;
return [{ json: { success: false, message: errorData.error || 'Validation failed', error: errorData.error || 'Invalid request data', timestamp: new Date().toISOString() } }];
// v1.0.0 - Validation error response

// Fallback Distance Calc - v1.0.0
// Build Google Maps request for missing transit time
const ctx = $('Prepare Async Context - Code').first().json;
const apiKey = $('Get Maps Key (Fallback) - Supabase').first().json.value;

if (!apiKey) {
  return [{ json: {
    ...ctx,
    fallbackError: 'Google Maps API key not found',
    stepResults: { ...ctx.stepResults, fallback_transit_calc: 'failed_no_key' }
  } }];
}

const origins = ctx.pickup_address || '';
const destinations = ctx.locationAddress || '';

if (!origins || !destinations) {
  return [{ json: {
    ...ctx,
    fallbackError: 'Missing pickup or destination address',
    stepResults: { ...ctx.stepResults, fallback_transit_calc: 'failed_no_address' }
  } }];
}

return [{ json: {
  ...ctx,
  fb_apiKey: apiKey,
  fb_origins: origins,
  fb_destinations: destinations
} }];
// v1.0.0 - Prepare fallback distance request

// Process Fallback Result - v1.0.0
// Extract distance/duration, update appointment timing
const ctx = $('Fallback Distance Calc - Code').first().json;
const mapResult = $input.first().json;
const stepResults = ctx.stepResults || {};

if (ctx.fallbackError) {
  return [{ json: { ...ctx, stepResults: { ...stepResults, fallback_transit_calc: 'failed' } } }];
}

const el = mapResult.rows?.[0]?.elements?.[0];
if (!el || el.status !== 'OK') {
  console.error('Fallback Maps API failed: ' + (el?.status || 'no response'));
  return [{ json: {
    ...ctx,
    stepResults: { ...stepResults, fallback_transit_calc: 'failed_api_error' }
  } }];
}

const rawMin = Math.ceil(el.duration.value / 60);
// Apply +5 min buffer and round to nearest 5
const transitMin = Math.ceil((rawMin + 5) / 5) * 5;
const distKm = parseFloat((el.distance.value / 1000).toFixed(2));

// Recalculate pickup and dropoff with new transit
const apptDT = new Date(ctx.appointmentDateTime);
const apptLen = ctx.appointmentLength || 120;
const apptType = ctx.appointment_type || 'round_trip';
const dir = ctx.trip_direction || 'to_clinic';

let newPickup, newDropOff;
if (apptType === 'one_way') {
  if (dir === 'to_home') {
    newPickup = apptDT.toISOString();
    newDropOff = new Date(apptDT.getTime() + (transitMin * 60000)).toISOString();
  } else {
    newPickup = new Date(apptDT.getTime() - (transitMin * 60000)).toISOString();
    newDropOff = apptDT.toISOString();
  }
} else {
  newPickup = new Date(apptDT.getTime() - (transitMin * 60000)).toISOString();
  const total = apptLen + transitMin;
  newDropOff = new Date(apptDT.getTime() + (total * 60000)).toISOString();
}

return [{ json: {
  ...ctx,
  fb_transitMinutes: transitMin,
  fb_distanceKm: distKm,
  fb_newPickupTime: newPickup,
  fb_newDropOffTime: newDropOff,
  fb_clinicName: ctx.location,
  fb_clinicId: ctx.clinic_id,
  stepResults: {
    ...stepResults,
    fallback_transit_calc: 'completed',
    fallback_transit_minutes: transitMin,
    fallback_distance_km: distKm
  }
} }];
// v1.0.0 - Process fallback result with buffer

// Merge Client Travel Times - v1.0.0
// Merge fallback result into client clinic_travel_times JSONB
const ctx = $('Process Fallback Result - Code').first().json;
const client = $input.first().json;
const clinicName = ctx.fb_clinicName;

if (!clinicName || !ctx.fb_transitMinutes) {
  return [{ json: { ...ctx, fb_mergeSkipped: 'true' } }];
}

// Get existing travel times or empty object
let travelTimes = client.clinic_travel_times || {};
if (typeof travelTimes === 'string') {
  try { travelTimes = JSON.parse(travelTimes); }
  catch(e) { travelTimes = {}; }
}

// Determine address type based on pickup_address match
const pickupAddr = (ctx.pickup_address || '').toLowerCase().trim();
const primaryAddr = [
  client.civicaddress, client.city,
  client.prov, client.postalcode
].filter(Boolean).join(', ').toLowerCase().trim();

let addressType = 'primary';
if (client.secondary_civic_address) {
  const secAddr = [
    client.secondary_civic_address, client.secondary_city,
    client.secondary_province, client.secondary_postal_code
  ].filter(Boolean).join(', ').toLowerCase().trim();
  if (pickupAddr === secAddr) {
    addressType = 'secondary';
  }
}

// Merge: preserve existing entries, add/update this clinic
if (!travelTimes[clinicName]) {
  travelTimes[clinicName] = {};
}

travelTimes[clinicName][addressType] = {
  duration_minutes: ctx.fb_transitMinutes,
  distance_km: ctx.fb_distanceKm,
  calculated_at: new Date().toISOString()
};

return [{ json: {
  ...ctx,
  fb_mergedTravelTimes: travelTimes,
  fb_addressType: addressType,
  fb_mergeSkipped: 'false'
} }];
// v1.0.0 - Merge fallback into clinic_travel_times

// Restore Fallback Data - v1.0.0
// Delete node loses input; restore from upstream
const ctx = $('Process Fallback Result - Code').first().json;
const client = $('Get Client for Merge - Supabase').first().json;
const mergeData = $('Merge Client Travel Times - Code').first().json;

return [{ json: {
  client_id: client.id,
  destination_id: ctx.fb_clinicId,
  primary_distance_km: mergeData.fb_addressType === 'primary' ? ctx.fb_distanceKm : null,
  primary_duration_minutes: mergeData.fb_addressType === 'primary' ? ctx.fb_transitMinutes : null,
  secondary_distance_km: mergeData.fb_addressType === 'secondary' ? ctx.fb_distanceKm : null,
  secondary_duration_minutes: mergeData.fb_addressType === 'secondary' ? ctx.fb_transitMinutes : null
} }];
// v1.0.0 - Restore data after delete

// Prepare Distance Request - v1.0.0
const data = $('Prepare Async Context - Code').first().json;
const apiKey = $('Get Maps API Key - Supabase').first().json.value;

if (!apiKey) {
  return [{ json: { ...data, trafficError: 'Google Maps API key not found', stepResults: { ...data.stepResults, traffic_calc: 'failed_no_key' } } }];
}

const apptType = data.appointment_type || 'round_trip';
const direction = data.trip_direction || 'to_clinic';
let origins = data.pickup_address || '';
let destinations = data.locationAddress || '';

if (apptType === 'one_way' && direction === 'to_home') {
  origins = data.locationAddress || '';
  destinations = data.pickup_address || '';
}

const departureTime = Math.floor(new Date(data.appointmentDateTime).getTime() / 1000);

return [{ json: { ...data, apiKey: apiKey, origins: origins, destinations: destinations, departureTime: departureTime } }];
// v1.0.0 - Prepare distance request

// Process Traffic Result - v1.0.0
const data = $('Prepare Distance Request - Code').first().json;
const mapResult = $input.first().json;
const stepResults = data.stepResults || {};

if (data.trafficError) {
  return [{ json: { ...data, stepResults: { ...stepResults, traffic_calc: 'failed' } } }];
}

const el = mapResult.rows?.[0]?.elements?.[0];
if (!el || el.status !== 'OK') {
  return [{ json: { ...data, stepResults: { ...stepResults, traffic_calc: 'failed_api_error' } } }];
}

const noTraffic = el.duration.value;
const pessimistic = el.duration_in_traffic ? el.duration_in_traffic.value : noTraffic;
const p75sec = noTraffic + (pessimistic - noTraffic) * 0.75;
const p75min = Math.ceil(p75sec / 60);
const rounded = Math.ceil(p75min / 5) * 5;
const newTransit = Math.max(rounded, 5);
const distKm = parseFloat((el.distance.value / 1000).toFixed(2));

const apptDT = new Date(data.appointmentDateTime);
const apptLen = data.appointmentLength || 120;
const apptType = data.appointment_type || 'round_trip';
const dir = data.trip_direction || 'to_clinic';

let newPickup, newDropOff;
if (apptType === 'one_way') {
  if (dir === 'to_home') {
    newPickup = apptDT.toISOString();
    newDropOff = new Date(apptDT.getTime() + (newTransit * 60000)).toISOString();
  } else {
    newPickup = new Date(apptDT.getTime() - (newTransit * 60000)).toISOString();
    newDropOff = apptDT.toISOString();
  }
} else {
  newPickup = new Date(apptDT.getTime() - (newTransit * 60000)).toISOString();
  const total = apptLen + newTransit;
  newDropOff = new Date(apptDT.getTime() + (total * 60000)).toISOString();
}

return [{ json: { ...data, newTransitTime: newTransit, newPickupTime: newPickup, newDropOffTime: newDropOff, driverTotalDistance: distKm, stepResults: { ...stepResults, traffic_calc: 'completed', traffic_transit_minutes: newTransit, traffic_distance_km: distKm } } }];
// v1.0.0 - Process traffic result

// Prepare Calendar Event - v2.1.0
const ctx = $('Prepare Async Context - Code').first().json;
const appointment = $('Get Updated Appt - Supabase').first().json;
const client = $('Get Client - Supabase').first().json;
const driver = $('Get New Driver - Supabase').first().json;

if (!driver || !driver.google_calendar_id) {
  return [{ json: { ...ctx, calendarError: 'Driver has no calendar', stepResults: { ...ctx.stepResults, calendar_sync: 'failed_no_calendar' } } }];
}

const pickupTime = new Date(appointment.pickuptime);
const apptTime = new Date(appointment.appointmenttime);
const dropOff = new Date(appointment.dropOffTime || apptTime.getTime() + (appointment.this_appointment_length * 60000));

const clientName = [client.firstname || '', client.lastname || ''].filter(Boolean).join(' ') || 'Unknown Client';
const clientAddr = [client.civicaddress, client.city, client.prov, client.postalcode].filter(Boolean).join(', ');

const apptType = appointment.appointment_type || 'round_trip';
const oneWayDir = appointment.trip_direction || 'to_clinic';
const supportName = appointment.event_name || 'Support Event';

let eventTitle;
if (apptType === 'one_way') {
  if (oneWayDir === 'to_home') { eventTitle = 'ONE-WAY: ' + clientName + ' \u2192 Home'; }
  else { eventTitle = 'ONE-WAY: ' + clientName + ' \u2192 ' + appointment.locationname; }
} else if (apptType === 'support') {
  eventTitle = 'SUPPORT: ' + supportName;
} else {
  eventTitle = 'Round Trip: ' + clientName + ' to ' + appointment.locationname;
}

let colorId = '2';
if (apptType === 'one_way') colorId = '6';
if (apptType === 'support') colorId = '3';

const timeOpts = { timeZone: 'America/Halifax', hour: 'numeric', minute: '2-digit', hour12: true };
const pickupStr = pickupTime.toLocaleString('en-US', timeOpts);
const apptStr = apptTime.toLocaleString('en-US', timeOpts);

const descLines = ['Client: ' + clientName, client.phone ? 'Phone: ' + client.phone : '', 'Type: ' + apptType.replace('_', ' ')];
if (apptType === 'one_way') descLines.push('Direction: ' + oneWayDir.replace('_', ' '));
descLines.push('Pickup: ' + pickupStr);
descLines.push('Appointment: ' + apptStr);
descLines.push('Duration: ' + appointment.this_appointment_length + ' min');
if (appointment.driver_instructions) descLines.push('Instructions: ' + appointment.driver_instructions);
if (appointment.scheduling_notes) descLines.push('Notes: ' + appointment.scheduling_notes);

let eventLocation = clientAddr;
if (apptType === 'support') eventLocation = appointment.locationaddress || 'See description';
else if (apptType === 'one_way' && oneWayDir === 'to_home') eventLocation = appointment.locationaddress || clientAddr;

const calEvent = { summary: eventTitle, description: descLines.filter(Boolean).join('\n'), start: { dateTime: appointment.pickuptime, timeZone: 'America/Halifax' }, end: { dateTime: dropOff.toISOString(), timeZone: 'America/Halifax' }, location: eventLocation, colorId: colorId, extendedProperties: { private: { rrts_appointment_id: appointment.id.toString(), rrts_driver_id: driver.id.toString(), rrts_appointment_type: apptType } }, reminders: { useDefault: false, overrides: [{ method: 'popup', minutes: 60 }, { method: 'popup', minutes: 5 }] } };

const operation = appointment.driver_calendar_event_id ? 'UPDATE' : 'CREATE';
const calUrl = operation === 'UPDATE' ? 'https://www.googleapis.com/calendar/v3/calendars/' + driver.google_calendar_id + '/events/' + appointment.driver_calendar_event_id : 'https://www.googleapis.com/calendar/v3/calendars/' + driver.google_calendar_id + '/events';

return [{ json: { ...ctx, calendarOperation: operation, calendarId: driver.google_calendar_id, calendarMethod: operation === 'UPDATE' ? 'PATCH' : 'POST', calendarUrl: calUrl, calendarEvent: calEvent } }];
// v2.1.0 - Support type uses venue address for calendar location

// Build Task Result - v2.0.0
// Collect per-step results including fallback transit
const ctx = $('Prepare Async Context - Code').first().json;
const stepResults = {};

// Step 0: Fallback transit calc
if (ctx.fallbackTransitNeeded === 'true') {
  try {
    const fbData = $('Process Fallback Result - Code').first().json;
    stepResults.fallback_transit_calc = fbData.stepResults?.fallback_transit_calc || 'completed';
    if (fbData.stepResults?.fallback_transit_minutes) {
      stepResults.fallback_transit_minutes = fbData.stepResults.fallback_transit_minutes;
    }
    if (fbData.stepResults?.fallback_distance_km) {
      stepResults.fallback_distance_km = fbData.stepResults.fallback_distance_km;
    }
  } catch (e) {
    stepResults.fallback_transit_calc = 'skipped';
  }
} else {
  stepResults.fallback_transit_calc = 'skipped';
}

// Step 1: Traffic calc
if (ctx.trafficCalcNeeded === 'true') {
  try {
    const trafficData = $('Process Traffic Result - Code').first().json;
    stepResults.traffic_calc = trafficData.stepResults?.traffic_calc || 'completed';
    if (trafficData.stepResults?.traffic_transit_minutes) {
      stepResults.traffic_transit_minutes = trafficData.stepResults.traffic_transit_minutes;
    }
    if (trafficData.stepResults?.traffic_distance_km) {
      stepResults.traffic_distance_km = trafficData.stepResults.traffic_distance_km;
    }
  } catch (e) {
    stepResults.traffic_calc = 'skipped';
  }
} else {
  stepResults.traffic_calc = 'skipped';
}

// Step 2: Calendar delete
if (ctx.needsDelete === 'true') {
  try {
    const delResult = $('Delete Old Calendar - HTTP').first().json;
    stepResults.calendar_delete = (delResult.error || delResult.code >= 400) ? 'failed' : 'completed';
  } catch (e) {
    stepResults.calendar_delete = 'failed';
  }
} else {
  stepResults.calendar_delete = 'skipped';
}

// Step 3: Calendar sync
if (ctx.needsSync === 'true') {
  try {
    const syncResult = $('Execute Calendar API - HTTP').first().json;
    stepResults.calendar_sync = (syncResult.error || !syncResult.id) ? 'failed' : 'completed';
  } catch (e) {
    stepResults.calendar_sync = 'failed';
  }
} else {
  stepResults.calendar_sync = 'skipped';
}

const hasFailed = Object.values(stepResults).some(v => v === 'failed');
const finalStatus = hasFailed ? 'failed' : 'completed';
const failedSteps = Object.entries(stepResults).filter(([k,v]) => v === 'failed').map(([k]) => k);
const errorMsg = hasFailed ? 'One or more async steps failed: ' + failedSteps.join(', ') : null;

return [{ json: {
  taskId: ctx.taskId,
  finalStatus: finalStatus,
  errorMessage: errorMsg,
  stepResults: stepResults
} }];
